async function solve() {
  const now = (await api.getCurrentDatetime()).now;
  const oneWeekAgo = new Date(new Date(now).getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();

  // Try to get transactions directly and count them
  const transactionsRes = await api.listTransactionsInWindow({
    fromIso: oneWeekAgo,
    toIso: now,
    limit: 50
  });

  const counts = {};
  for (const t of transactionsRes.transactions) {
    counts[t.customerId] = (counts[t.customerId] || 0) + 1;
  }

  let topCustomerId = null;
  let maxCount = 0;
  for (const cid in counts) {
    if (counts[cid] > maxCount) {
      maxCount = counts[cid];
      topCustomerId = cid;
    }
  }

  if (!topCustomerId) {
    // Fallback if no transactions found in first 50
    return {
      topCustomerId: null,
      topCustomerName: "None",
      transactionCount: 0,
      totalSpend: 0,
      averageSpend: 0,
      fromIso: oneWeekAgo,
      toIso: now
    };
  }

  const stats = await api.computeCustomerSpendStats({
    customerId: topCustomerId,
    fromIso: oneWeekAgo,
    toIso: now
  });

  // Search for the customer name
  const searchRes = await api.searchCustomersByName({ query: "", limit: 50 });
  const customer = searchRes.customers.find(c => c.id === topCustomerId);

  return {
    topCustomerId: topCustomerId,
    topCustomerName: customer ? customer.name : "Unknown",
    transactionCount: stats.transactionCount,
    totalSpend: stats.totalSpend,
    averageSpend: stats.averageSpend,
    fromIso: oneWeekAgo,
    toIso: now
  };
}

return await solve();

